// Coalesce dos 4 campos do form onde o link do Calendly pode chegar
const ans = $('Trata Webhook').item.json.response.answers;
const fields = ['699c88aa1d90fc4e0d0e5230','67f0b04758c5b6e203042d9f','67f0b04758c5b6e203042d9e','69d6ac7b10cc32f1a30ee034'];
let link = null;
for (const f of fields) {
  const c = ans[f] && ans[f].content;
  if (c && typeof c === 'string' && c.includes('calendly.com')) { link = c.trim(); break; }
}
let eventUuid = null;
if (link) {
  const m = link.match(/scheduled_events\/([0-9a-fA-F-]{36})/);
  if (m) eventUuid = m[1];
}
return [{ json: { ...$json, agendou: !!eventUuid, calendlyLink: link, eventUuid } }];

// Reembala a resposta do GET singular no mesmo formato do endpoint antigo
// (mantém todas as referências a collection[0] intactas)
return [{ json: { collection: [ $('3 · Busca evento (por link)').item.json.resource ] } }];

